{
  "level": "A2–C1",
  "intro": "W tym dziale w pełni opanujesz <strong>stronę bierną</strong> w języku angielskim: od podstawowych zasad tworzenia po bardziej złożone konstrukcje z bezokolicznikiem, gerundium i czasownikami modalnymi.",
  "rules": [
    {
      "label": "Podstawy",
      "color": "emerald",
      "text": "Podstawowa struktura to: <strong>Subject + be + Past Participle (V3)</strong>:",
      "example": "The cake is baked by my mother."
    },
    {
      "label": "Wszystkie czasy",
      "color": "blue",
      "text": "Strona bierna występuje w <strong>9 podstawowych czasach angielskich</strong>:",
      "example": "Present/Past/Future Simple, Continuous, Perfect"
    },
    {
      "label": "Modalne",
      "color": "rose",
      "text": "Strona bierna z <strong>czasownikami modalnymi</strong>:",
      "example": "This task must be done today."
    },
    {
      "label": "Bezokolicznik i gerundium",
      "color": "amber",
      "text": "Bierne formy <strong>bezokolicznika i gerundium</strong>:",
      "example": "to be done, being done, having been done"
    }
  ]
}

{
  "title": "1. Podstawowe zasady tworzenia strony biernej",
  "intro": "W stronie biernej podmiot odbiera czynność, a nie ją wykonuje:",
  "items": [
    {
      "label": "Active",
      "title": "Strona czynna",
      "subtitle": "Podmiot wykonuje czynność: Tom writes letters."
    },
    {
      "label": "Passive",
      "title": "Strona bierna",
      "subtitle": "Podmiot odbiera czynność: Letters are written by Tom."
    },
    {
      "label": "Wzór",
      "title": "be + V3",
      "subtitle": "Czasownik be w odpowiednim czasie + Past Participle."
    },
    {
      "label": "Agent",
      "title": "Wykonawca (by)",
      "subtitle": "by + agent stosujemy, gdy ważne jest, kto wykonuje czynność: by Tom."
    }
  ]
}

{
  "title": "2. Kiedy używamy strony biernej?",
  "sections": [
    {
      "label": "Nieznany wykonawca",
      "color": "emerald",
      "description": "Gdy wykonawca czynności jest <strong>nieznany albo nieistotny</strong>:",
      "examples": [
        {
          "en": "My bike was stolen yesterday.",
          "ua": "Mój rower został wczoraj skradziony."
        },
        {
          "en": "The window has been broken.",
          "ua": "Okno zostało wybite."
        }
      ]
    },
    {
      "label": "Nacisk na czynność",
      "color": "blue",
      "description": "Gdy ważniejsza jest <strong>sama czynność albo jej rezultat</strong> niż to, kto ją wykonał:",
      "examples": [
        {
          "en": "The report was submitted on time.",
          "ua": "Raport został złożony na czas."
        },
        {
          "en": "English is spoken in many countries.",
          "ua": "Angielskim mówi się w wielu krajach."
        }
      ]
    },
    {
      "label": "Styl formalny",
      "color": "rose",
      "description": "W <strong>stylu naukowym, urzędowym i biznesowym</strong>:",
      "examples": [
        {
          "en": "The experiment was conducted last month.",
          "ua": "Eksperyment przeprowadzono w zeszłym miesiącu."
        },
        {
          "en": "Applicants will be contacted by email.",
          "ua": "Z kandydatami skontaktujemy się mailowo."
        }
      ]
    }
  ]
}
